// Quiz content for Cours36 — Harmonie de Debussy et Ravel : l'impressionnisme approfondi

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours36Locale { questions: Question[]; }

const questionsFr: Question[] = [
  { q: "Quelle est la caractéristique harmonique principale du Prélude à l'après-midi d'un faune de Debussy ?", opts: ["Une progression classique V–I répétée toutes les 8 mesures", "Le premier accord (Fa#Maj7) est introduit sans préparation et n'a aucune fonction tonale — pure couleur sonore pendant 110 mesures sans cadence dominante-tonique", "Une fugue à 4 voix", "Une gamme par tons stricte pendant toute l'œuvre"], a: 1, fb: "Le Prélude à l'après-midi d'un faune (1894) est révolutionnaire : l'accord initial de Fa#Maj7 arrive sans contexte, sans préparation, comme une apparition. Les 110 mesures évitent soigneusement la cadence V→I classique. Debussy crée une 'harmonie flottante' — la musique existe dans le présent sonore, sans direction fonctionnelle." },
  { q: "Dans la pièce 'Voiles' de Debussy, quelles sont les deux gammes utilisées ?", opts: ["Gamme majeure et gamme mineure harmonique", "Gamme par tons (pour la section principale) et gamme pentatonique (pour la section centrale)", "Gamme octatonique et gamme lydienne", "Gamme chromatique et gamme par tons"], a: 1, fb: "'Voiles' est un chef-d'œuvre d'économie harmonique : la pièce entière utilise uniquement la gamme par tons (section principale, mesures 1–47 et 64–64+) et la gamme pentatonique (section centrale, mesures 48–63). Jamais les deux ensembles. Ce changement de gamme marque la seule 'modulation' de la pièce — sans accord pivot classique." },
  { q: "Qu'est-ce qu'une 'pédale longue' dans le style de Debussy ?", opts: ["Une note de basse répétée très rapidement", "Une basse immobile (note tenue ou répétée) pendant que l'harmonie change au-dessus, créant un effet de suspension harmonique", "Un accord tenu pendant toute une mesure", "Une note ornementale à la pédale du piano"], a: 1, fb: "La pédale longue est une technique d'organum médiéval réinventée par Debussy : la basse reste fixe (Do pendant 8 mesures) tandis que l'harmonie au-dessus se meut librement. L'effet est de suspension temporelle — le temps harmonique s'arrête à la basse pendant que la couleur change au-dessus. Très fréquent dans Pelléas et Mélisande." },
  { q: "Comment Debussy utilise-t-il les accords non fonctionnels ?", opts: ["Il les évite complètement et reste dans le système tonal classique", "Les accords suivent la ligne mélodique pour leur couleur sonore, pas des fonctions harmoniques T/SD/D — l'accord est une texture, pas un rôle", "Il les utilise uniquement dans les cadences", "Il les utilise seulement aux passages en gamme octatonique"], a: 1, fb: "Chez Debussy, l'accord n'a pas de rôle fonctionnel (tonique/dominante/sous-dominante) — il a une couleur. La succession d'accords suit la mélodie et l'image sonore, pas la logique tension-résolution. Analyser Debussy avec T/SD/D revient à appliquer les règles de l'échecs aux dés — la grille est inappropriée." },
  { q: "Qu'est-ce que l'homorythmie (planing) dans le style impressionniste ?", opts: ["Deux voix avec le même rythme mais des mélodies différentes", "Toutes les voix bougent au même rythme, avec le même type d'accord transposé — l'accord se déplace comme un bloc sonore", "Une technique de notation rythmique", "Un canon à la même hauteur"], a: 1, fb: "L'homorythmie ou planing : toutes les voix bougent ensemble au même rythme, en transportant le même type d'accord. Un accord de 6te glisse sur une gamme — toutes les voix bougent ensemble. Les quintes parallèles sont intentionnelles — elles créent l'effet de 'bloc glissant' caractéristique de Debussy." },
  { q: "Quel est l'effet harmonique des 'quintes ouvertes médiévales' utilisées par Debussy ?", opts: ["Elles créent une tension dissonante moderne", "Elles créent un effet de pureté archaïque, sonné de cloches ou de plain-chant — retour à une consonance 'pré-tonale' sans tierce ni quarte", "Elles remplacent les accords de 7e dominante", "Elles évoquent toujours la musique japonaise"], a: 1, fb: "Les quintes ouvertes (fondamentale + quinte, sans tierce) évoquent l'organum médiéval et le plain-chant. Sans tierce, elles n'ont ni qualité majeure ni mineure — elles sonnent pures et atemporelles. Debussy les utilise pour des effets de vide, d'espace ou d'archaïsme (La Cathédrale Engloutie commence avec des quintes)." },
  { q: "Quelle gamme Debussy utilise-t-il pour créer le 'flottement total' sans note directrice ?", opts: ["Gamme mineure mélodique", "Gamme par tons — 6 tons entiers sans demi-ton, donc sans sensible ni sous-sensible", "Gamme octatonique", "Gamme phrygienne"], a: 1, fb: "La gamme par tons (Do–Ré–Mi–Fa#–Sol#–La#) n'a aucun demi-ton — donc aucune tension directrice. Pas de sensible qui tire vers la tonique, pas de triton qui attire la résolution. Tous les accords construits sur cette gamme sont augmentés. L'effet est le flottement total — la musique ne 'veut' nulle part." },
  { q: "Comment analyser la structure d'une pièce impressionniste si les fonctions T/SD/D ne s'appliquent pas ?", opts: ["On ne peut pas l'analyser", "Par couleurs et registres : identifier les gammes sources, les effets de texture (planing, pédale), les changements de couleur sonore et les zones de densité harmonique", "Par analyse schenkérienne stricte", "Par comparaison avec les formes classiques (sonate, rondo)"], a: 1, fb: "L'analyse impressionniste identifie : 1/ La gamme source (par tons, octatonique, pentatonique) ; 2/ La technique de texture (planing, pédale, quintes ouvertes) ; 3/ La couleur de l'accord (qualité, extensions) ; 4/ Le registre et la dynamique. Ces 4 paramètres remplacent l'analyse fonctionnelle classique dans la musique de Debussy." },
  { q: "Pelléas et Mélisande de Debussy est souvent cité comme modèle d'harmonie impressionniste. Pourquoi ?", opts: ["Parce qu'il utilise exclusivement des accords de 7e de dominante", "Parce que l'harmonie suit les émotions et sous-textes des personnages sans jamais utiliser de cadence V–I classique pour ponctuer — l'harmonie 'coule' comme les émotions", "Parce qu'il est composé entièrement en mode lydien", "Parce qu'il utilise le dodécaphonisme"], a: 1, fb: "Pelléas et Mélisande (1902) est une révolution opératique : l'harmonie évite systématiquement les cadences V→I marquées. Les dialogues harmoniques suivent le flux émotionnel des personnages — l'accord change quand l'émotion change, pas quand la forme musicale le demande. C'est une dramaturgie harmonique entièrement nouvelle." },
  { q: "Qu'est-ce que la 'musique d'ameublement' inventée par Satie et en quoi préfigure-t-elle la musique moderne ?", opts: ["De la musique pour meubler les silences d'un opéra", "Une musique faite pour ne pas être écoutée — fond sonore sans tension ni résolution, précurseur de la musique ambient et du minimalisme", "Une technique de composition pour piano solo", "Un style de musique baroque réinventé"], a: 1, fb: "Satie a inventé la 'musique d'ameublement' (1920) — une musique censée se confondre avec le bruit de l'environnement, comme un meuble sonore. Elle n'a pas de tension dramatique ni de résolution. Satie préfigurait Brian Eno (musique ambient), Steve Reich (minimalisme) et la musique lounge de 50 ans. Sa première exécution : le public s'assit et écouta — Satie furieux cria 'N'écoutez pas !'" },
  { q: "Qu'est-ce qu'un 'polyaccord' (polytonalité accordale) dans le style de Ravel ?", opts: ["Un accord joué par plusieurs instruments", "La superposition de deux accords complets et reconnaissables — CMaj + DMaj = un nouveau cluster harmonique hybride", "Un accord avec 7 notes", "Un accord joué très rapidement en arpège"], a: 1, fb: "Chez Ravel, la superposition de deux accords distincts crée une couleur nouvelle. Do Majeur + Ré Majeur = Do–Mi–Sol–Ré–Fa#–La. Les 6 notes ne constituent plus un accord simple — c'est une superposition de deux accords reconnaissables. Ravel calcule précisément quelles notes créer une couleur riche sans devenir un cluster sans logique." },
  { q: "Comment Ravel crée-t-il une tension progressive dans le Boléro sans changer d'accord ?", opts: ["Il accélère le tempo progressivement", "Il ajoute des instruments successivement — l'orchestration densifie, le registre s'élargit, le volume augmente. Un seul accord de Do7 pendant 15 minutes.", "Il module vers des tonalités lointaines", "Il change le rythme toutes les 8 mesures"], a: 1, fb: "Le Boléro est un tour de force orchestral unique : un seul accord (Do majeur/Do7) et une seule mélodie répétée 18 fois. La tension vient uniquement de l'orchestration progressive — de la flûte solo à l'orchestre complet. C'est la démonstration que la progression harmonique n'est pas le seul moteur de tension dans la musique." },
  { q: "Quelle est la différence fondamentale entre l'approche compositionnelle de Debussy et celle de Ravel ?", opts: ["Debussy compose pour orchestre, Ravel pour piano uniquement", "Debussy crée intuitivement par images et couleurs sonores ; Ravel calcule avec une rigueur architecturale — même surface impressionniste, logiques opposées", "Debussy utilise les modes, Ravel uniquement le système tonal classique", "Il n'y a aucune différence stylistique entre eux"], a: 1, fb: "Debussy : composition organique, intuitive, suivant la couleur et l'image sonore. Ravel : composition architecturale, calculée, avec une rigueur quasi mathématique (il disait avoir 'l'esprit d'un horloger'). Même surface impressionniste (accords colorés, gammes spéciales), logiques compositionnelles opposées. Debussy lui-même les distinguait clairement." },
  { q: "Qu'est-ce que la 'modalité néoclassique' de Ravel ?", opts: ["Utiliser les modes ecclésiastiques en style baroque", "Retourner aux modes anciens (dorien, phrygien, lydien) dans un langage musical moderne — la Pavane pour une infante défunte est en mode dorien sur Sol mineur", "Composer en style classique viennois avec des ornements modaux", "Utiliser uniquement la gamme majeure modale"], a: 1, fb: "La modalité néoclassique chez Ravel signifie utiliser les modes ecclésiastiques (dorien, phrygien, lydien) dans un contexte harmonique moderne. La Pavane pour une infante défunte est en Sol mineur dorien (avec Mib naturel, pas de sensible de Fa#). L'accord résolutif final est purement modal — pas de cadence V7→Im classique." },
  { q: "Comment la note ajoutée (6te ou 9e) transforme-t-elle la couleur d'un accord majeur dans le style ravélien ?", opts: ["Elle le rend mineur", "Elle ajoute une brillance, une richesse ou une douceur spécifique — CMaj6 (Do–Mi–Sol–La) sonne plus 'doux' et jazz que CMaj simple", "Elle crée une dissonance non résolue", "Elle le rend identique à un accord augmenté"], a: 1, fb: "La 6te ajoutée sur un accord majeur (CMaj6 : Do–Mi–Sol–La) ou la 9e ajoutée (Cadd9 : Do–Mi–Sol–Ré) enrichissent la couleur sans ajouter de tension fonctionnelle (pas de 7te). CMaj6 sonne presque comme Am7 en second renversement — ambiguïté tendre. Ravel utilise ces 'accords enrichis' pour créer sa couleur harmonique caractéristique." },
  { q: "Quelle est la caractéristique harmonique principale des Gymnopédies de Satie ?", opts: ["Progressions rapides et chromatiques", "Accords de 7e majeure lentes en balancement — Dmaj7–Gmaj7 ou similaire — harmonie statique et hypnotique sans développement dramatique", "Fugues à 4 voix", "Gamme octatonique tout au long de l'œuvre"], a: 1, fb: "Les Gymnopédies (1888) utilisent des accords de 7e majeure en balancement lent — typiquement un accord 'I' et un accord 'IV' en alternance répétée. L'harmonie ne progresse pas dramatiquement — elle bascule entre deux couleurs. Cet effet statique et hypnotique est une révolution : la musique n'a pas de 'destination' harmonique." },
  { q: "Quel compositeur de musique ambient du XXe siècle est le plus souvent cité comme 'héritier' de Satie ?", opts: ["John Williams", "Brian Eno — son album 'Ambient 1: Music for Airports' (1978) applique exactement la philosophie de la 'musique d'ameublement'", "Miles Davis", "Philip Glass"], a: 1, fb: "Brian Eno a explicitement cité Satie comme inspiration pour ses albums ambient. 'Music for Airports' (1978) est la réalisation moderne de la 'musique d'ameublement' : musique pour ne pas être écoutée attentivement, qui se fond dans l'environnement. Eno a inventé le terme 'ambient music' en référence directe à Satie." },
  { q: "Qu'est-ce que la technique de 'vexations' de Satie ?", opts: ["Un procédé de composition chromatique", "Une pièce de 180 notes répétées 840 fois d'affilée (environ 18 heures de musique) — premier exemple de minimalisme radical et de performance durée", "Une technique de pédales longues", "Un accord répété en crescendo"], a: 1, fb: "'Vexations' (1893) de Satie est une partition de 52 secondes avec la mention 'à jouer 840 fois de suite'. La première exécution intégrale par John Cage et 12 pianistes en relais a duré 18h40 en 1963. C'est le premier acte du minimalisme radical et de l'art durée — 70 ans avant Steve Reich et Philip Glass." },
  { q: "Comment Debussy et Ravel ont-ils réagi à être regroupés sous l'étiquette 'impressionniste' ?", opts: ["Ils ont tous deux accepté et adopté le terme avec enthousiasme", "Debussy détestait ce terme emprunté à la peinture ; Ravel ne le revendiquait pas non plus — tous deux se considéraient simplement comme compositeurs de musique française", "Ils ont inventé le terme eux-mêmes", "Ils ont écrit ensemble un manifeste sur l'impressionnisme musical"], a: 1, fb: "Debussy en particulier rejetait vivement le terme 'impressionniste' emprunté à la critique picturale. Il se définissait comme compositeur français cherchant 'quelque chose d'autre'. Ravel était plus ambigu mais ne revendiquait pas non plus l'étiquette. L'impressionnisme musical est une catégorie créée par les critiques, pas les compositeurs eux-mêmes." },
  { q: "Quelle est la progression harmonique caractéristique de la Pavane pour une infante défunte de Ravel ?", opts: ["Entièrement en gamme par tons sans accord fonctionnel", "Progressions modales en Sol mineur dorien — absence de sensible (Fa# → Fa naturel), cadences modales qui évitent la tonique au sens classique", "II–V–I en Do mineur répété", "Cycle de quintes en mode majeur uniquement"], a: 1, fb: "La Pavane de Ravel est en Sol mineur dorien (le dorien a un 6e degré naturel — Mib devient Mi naturel). Les cadences utilisent le IVm (Do mineur) et le bVII (Fa Maj) — des harmonies modales, pas tonales. L'accord final n'est pas un V7→Im classique mais une cadence modale plus douce. C'est la modalité néoclassique ravélienne en action." },
];

const questionsEn: Question[] = [
  { q: "What is the main harmonic characteristic of Debussy's Prélude à l'après-midi d'un faune?", opts: ["A classical V–I progression repeated every 8 bars", "The opening chord (F#Maj7) appears without preparation and has no tonal function — pure sonic color for 110 bars with no dominant-to-tonic cadence", "A four-voice fugue", "A strict whole-tone scale throughout the work"], a: 1, fb: "The Prélude à l'après-midi d'un faune (1894) is revolutionary: the opening F#Maj7 chord arrives without context, without preparation, like an apparition. The 110 bars carefully avoid the classical V→I cadence. Debussy creates a 'floating harmony' — the music exists in the sonic present, without functional direction." },
  { q: "In Debussy's piece 'Voiles', which two scales are used?", opts: ["Major scale and harmonic minor scale", "Whole-tone scale (main section) and pentatonic scale (central section)", "Octatonic scale and Lydian scale", "Chromatic scale and whole-tone scale"], a: 1, fb: "'Voiles' is a masterpiece of harmonic economy: the entire piece uses only the whole-tone scale (main section, bars 1–47 and 64+) and the pentatonic scale (central section, bars 48–63). Never both at once. This change of scale marks the only 'modulation' in the piece — without a classical pivot chord." },
  { q: "What is a 'long pedal point' in Debussy's style?", opts: ["A bass note repeated very rapidly", "An immobile bass (held or repeated note) while the harmony changes above, creating a harmonic suspension effect", "A chord held for an entire bar", "An ornamental note at the piano pedal"], a: 1, fb: "The long pedal point is a medieval organum technique reinvented by Debussy: the bass stays fixed (C for 8 bars) while the harmony above moves freely. The effect is temporal suspension — harmonic time stops at the bass while the color changes above. Very frequent in Pelléas et Mélisande." },
  { q: "How does Debussy use non-functional chords?", opts: ["He avoids them entirely and stays within the classical tonal system", "Chords follow the melodic line for their sonic color, not harmonic functions T/SD/D — the chord is a texture, not a role", "He uses them only in cadences", "He uses them only in octatonic passages"], a: 1, fb: "In Debussy, a chord has no functional role (tonic/dominant/subdominant) — it has a color. The chord succession follows the melody and sonic image, not tension-resolution logic. Analyzing Debussy with T/SD/D is like applying chess rules to dice — the framework is inappropriate." },
  { q: "What is planing (homorhythm) in the impressionist style?", opts: ["Two voices with the same rhythm but different melodies", "All voices move at the same rhythm, with the same chord type transposed — the chord slides as a sonic block", "A rhythmic notation technique", "A canon at the same pitch"], a: 1, fb: "Planing or homorhythm: all voices move together at the same rhythm, carrying the same chord type. A sixth chord slides across a scale — all voices move together. The parallel fifths are intentional — they create the characteristic 'sliding block' effect of Debussy." },
  { q: "What is the harmonic effect of the 'medieval open fifths' used by Debussy?", opts: ["They create modern dissonant tension", "They create an effect of archaic purity, like bells or plainchant — a return to 'pre-tonal' consonance without third or fourth", "They replace dominant seventh chords", "They always evoke Japanese music"], a: 1, fb: "Open fifths (root + fifth, no third) evoke medieval organum and plainchant. Without a third, they have neither major nor minor quality — they sound pure and timeless. Debussy uses them for effects of emptiness, space, or archaism (La Cathédrale Engloutie opens with fifths)." },
  { q: "Which scale does Debussy use to create 'total floating' with no leading tone?", opts: ["Melodic minor scale", "Whole-tone scale — 6 whole tones without a semitone, therefore no leading tone or subtonic", "Octatonic scale", "Phrygian scale"], a: 1, fb: "The whole-tone scale (C–D–E–F#–G#–A#) has no semitone — therefore no directional tension. No leading tone pulling toward the tonic, no tritone attracting resolution. All chords built on this scale are augmented. The effect is total floating — the music 'wants' to go nowhere." },
  { q: "How do you analyze the structure of an impressionist piece if T/SD/D functions don't apply?", opts: ["You cannot analyze it", "By colors and registers: identify source scales, texture effects (planing, pedal), changes in sonic color and zones of harmonic density", "By strict Schenkerian analysis", "By comparison with classical forms (sonata, rondo)"], a: 1, fb: "Impressionist analysis identifies: 1/ The source scale (whole-tone, octatonic, pentatonic); 2/ The texture technique (planing, pedal, open fifths); 3/ The chord color (quality, extensions); 4/ The register and dynamics. These 4 parameters replace classical functional analysis in Debussy's music." },
  { q: "Debussy's Pelléas et Mélisande is often cited as a model of impressionist harmony. Why?", opts: ["Because it exclusively uses dominant seventh chords", "Because the harmony follows the characters' emotions and subtexts without ever using a classical V–I cadence to punctuate — the harmony 'flows' like emotions", "Because it is composed entirely in Lydian mode", "Because it uses twelve-tone serialism"], a: 1, fb: "Pelléas et Mélisande (1902) is an operatic revolution: the harmony systematically avoids marked V→I cadences. The harmonic dialogues follow the characters' emotional flow — the chord changes when the emotion changes, not when the musical form demands it. An entirely new harmonic dramaturgy." },
  { q: "What is Satie's 'furniture music' and how does it foreshadow modern music?", opts: ["Music to fill the silences of an opera", "Music made not to be listened to — sonic background without tension or resolution, precursor of ambient music and minimalism", "A composition technique for solo piano", "A reinvented baroque music style"], a: 1, fb: "Satie invented 'furniture music' (1920) — music meant to blend with environmental noise, like sonic furniture. It has no dramatic tension or resolution. Satie prefigured Brian Eno (ambient music), Steve Reich (minimalism), and lounge music by 50 years. Its premiere: the audience sat and listened — an enraged Satie shouted 'Don't listen!'" },
  { q: "What is a 'polyaccord' (chordal polytonality) in Ravel's style?", opts: ["A chord played by several instruments", "The superimposition of two complete, recognizable chords — CMaj + DMaj = a new hybrid harmonic cluster", "A chord with 7 notes", "A chord played very rapidly as an arpeggio"], a: 1, fb: "In Ravel, superimposing two distinct chords creates a new color. C Major + D Major = C–E–G–D–F#–A. The 6 notes no longer form a simple chord — it's a superimposition of two recognizable chords. Ravel precisely calculates which notes create a rich color without becoming a cluster with no logic." },
  { q: "How does Ravel create progressive tension in the Bolero without changing chord?", opts: ["He gradually speeds up the tempo", "He successively adds instruments — the orchestration densifies, the register widens, the volume increases. A single C7 chord for 15 minutes.", "He modulates to distant keys", "He changes the rhythm every 8 bars"], a: 1, fb: "The Bolero is a unique orchestral tour de force: a single chord (C major/C7) and a single melody repeated 18 times. The tension comes solely from progressive orchestration — from solo flute to full orchestra. It demonstrates that harmonic progression is not the only motor of tension in music." },
  { q: "What is the fundamental difference between Debussy's and Ravel's compositional approach?", opts: ["Debussy composes for orchestra, Ravel only for piano", "Debussy creates intuitively through sonic images and colors; Ravel calculates with architectural rigor — same impressionist surface, opposite logics", "Debussy uses modes, Ravel only the classical tonal system", "There is no stylistic difference between them"], a: 1, fb: "Debussy: organic, intuitive composition following color and sonic image. Ravel: architectural, calculated composition with near-mathematical rigor (he said he had 'the mind of a clockmaker'). Same impressionist surface (colored chords, special scales), opposite compositional logics. Debussy himself clearly distinguished between them." },
  { q: "What is Ravel's 'neo-classical modality'?", opts: ["Using ecclesiastical modes in baroque style", "Returning to ancient modes (Dorian, Phrygian, Lydian) in a modern musical language — the Pavane pour une infante défunte is in Dorian mode on G minor", "Composing in Viennese classical style with modal ornaments", "Using only the modal major scale"], a: 1, fb: "Neo-classical modality in Ravel means using ecclesiastical modes (Dorian, Phrygian, Lydian) in a modern harmonic context. The Pavane pour une infante défunte is in G Dorian minor (with natural Eb, no F# leading tone). The final resolving chord is purely modal — no classical V7→Im cadence." },
  { q: "How does an added note (6th or 9th) transform the color of a major chord in Ravel's style?", opts: ["It makes it minor", "It adds a specific brilliance, richness, or sweetness — CMaj6 (C–E–G–A) sounds more 'tender' and jazz-like than plain CMaj", "It creates an unresolved dissonance", "It makes it identical to an augmented chord"], a: 1, fb: "An added 6th on a major chord (CMaj6: C–E–G–A) or added 9th (Cadd9: C–E–G–D) enriches the color without adding functional tension (no 7th). CMaj6 sounds almost like Am7 in second inversion — tender ambiguity. Ravel uses these 'enriched chords' to create his characteristic harmonic color." },
  { q: "What is the main harmonic characteristic of Satie's Gymnopédies?", opts: ["Fast and chromatic progressions", "Slow rocking major seventh chords — Dmaj7–Gmaj7 or similar — static and hypnotic harmony with no dramatic development", "Four-voice fugues", "Octatonic scale throughout the work"], a: 1, fb: "The Gymnopédies (1888) use major seventh chords in slow rocking — typically a 'I' chord and a 'IV' chord in repeated alternation. The harmony does not progress dramatically — it alternates between two colors. This static, hypnotic effect is a revolution: the music has no harmonic 'destination'." },
  { q: "Which 20th-century ambient composer is most often cited as Satie's 'heir'?", opts: ["John Williams", "Brian Eno — his album 'Ambient 1: Music for Airports' (1978) applies exactly the philosophy of 'furniture music'", "Miles Davis", "Philip Glass"], a: 1, fb: "Brian Eno explicitly cited Satie as inspiration for his ambient albums. 'Music for Airports' (1978) is the modern realization of 'furniture music': music not meant to be listened to attentively, blending into the environment. Eno invented the term 'ambient music' in direct reference to Satie." },
  { q: "What is Satie's 'Vexations' technique?", opts: ["A chromatic composition process", "A piece of 180 notes repeated 840 times in succession (about 18 hours of music) — first example of radical minimalism and durational performance", "A long pedal-point technique", "A chord repeated in crescendo"], a: 1, fb: "'Vexations' (1893) by Satie is a 52-second score marked 'to be played 840 times in a row'. Its first complete performance by John Cage and 12 relay pianists lasted 18h40 in 1963. It is the first act of radical minimalism and duration art — 70 years before Steve Reich and Philip Glass." },
  { q: "How did Debussy and Ravel react to being grouped under the 'impressionist' label?", opts: ["Both enthusiastically accepted and adopted the term", "Debussy hated this term borrowed from painting; Ravel didn't claim it either — both simply considered themselves composers of French music", "They invented the term themselves", "They co-wrote a manifesto on musical impressionism"], a: 1, fb: "Debussy in particular strongly rejected the 'impressionist' label borrowed from pictorial criticism. He defined himself as a French composer seeking 'something else'. Ravel was more ambiguous but also did not claim the label. Musical impressionism is a category created by critics, not the composers themselves." },
  { q: "What is the characteristic harmonic progression of Ravel's Pavane pour une infante défunte?", opts: ["Entirely in whole-tone scale with no functional chord", "Modal progressions in G Dorian minor — absence of leading tone (F# → F natural), modal cadences avoiding the tonic in the classical sense", "Repeated II–V–I in C minor", "Circle of fifths in major mode only"], a: 1, fb: "Ravel's Pavane is in G Dorian minor (Dorian has a natural 6th degree — Eb becomes E natural). The cadences use IVm (C minor) and bVII (F Major) — modal harmonies, not tonal. The final chord is not a classical V7→Im but a softer modal cadence. This is Ravel's neo-classical modality in action." },
];

const questionsDe: Question[] = [
  { q: "Was ist das hauptsächliche harmonische Merkmal von Debussys Prélude à l'après-midi d'un faune?", opts: ["Eine klassische V–I-Progression alle 8 Takte wiederholt", "Der Eröffnungsakkord (Fis-Maj7) erscheint ohne Vorbereitung und hat keine tonale Funktion — reine Klangfarbe über 110 Takte ohne Dominante-Tonika-Kadenz", "Eine vierstimmige Fuge", "Eine strenge Ganztonleiter durch das gesamte Werk"], a: 1, fb: "Das Prélude à l'après-midi d'un faune (1894) ist revolutionär: Der Eröffnungsakkord Fis-Maj7 erscheint ohne Kontext, ohne Vorbereitung, wie eine Erscheinung. Die 110 Takte vermeiden sorgfältig die klassische V→I-Kadenz. Debussy schafft eine schwebende Harmonik — die Musik existiert im klanglichen Gegenwärtigen, ohne funktionale Richtung." },
  { q: "Welche zwei Tonleitern werden in Debussys Stück 'Voiles' verwendet?", opts: ["Dur-Tonleiter und harmonische Moll-Tonleiter", "Ganztonleiter (Hauptabschnitt) und Pentatonik (Mittelabschnitt)", "Oktatonische Tonleiter und Lydische Tonleiter", "Chromatische Tonleiter und Ganztonleiter"], a: 1, fb: "'Voiles' ist ein Meisterwerk der harmonischen Ökonomie: Das gesamte Stück verwendet nur die Ganztonleiter (Hauptabschnitt, Takte 1–47 und 64+) und die Pentatonik (Mittelabschnitt, Takte 48–63). Nie beide gleichzeitig. Dieser Tonleiterwechsel markiert die einzige 'Modulation' des Stücks — ohne klassischen Drehpunktakkord." },
  { q: "Was ist ein 'langer Orgelpunkt' in Debussys Stil?", opts: ["Eine sehr schnell wiederholte Bassnote", "Ein unbewegter Bass (gehaltene oder wiederholte Note), während sich die Harmonie darüber verändert und einen harmonischen Schwebezustand erzeugt", "Ein Akkord, der einen ganzen Takt lang gehalten wird", "Eine Verzierungsnote am Klavierpedal"], a: 1, fb: "Der lange Orgelpunkt ist eine mittelalterliche Organum-Technik, die Debussy neu erfindet: Der Bass bleibt fest (C über 8 Takte), während sich die Harmonie darüber frei bewegt. Der Effekt ist eine zeitliche Suspension — die harmonische Zeit stoppt am Bass, während sich die Farbe darüber ändert. Sehr häufig in Pelléas et Mélisande." },
  { q: "Wie verwendet Debussy nicht-funktionale Akkorde?", opts: ["Er vermeidet sie vollständig und bleibt im klassischen tonalen System", "Akkorde folgen der melodischen Linie ihrer Klangfarbe wegen, nicht den harmonischen Funktionen T/SD/D — der Akkord ist eine Textur, keine Rolle", "Er verwendet sie nur in Kadenzen", "Er verwendet sie nur in oktatonischen Passagen"], a: 1, fb: "Bei Debussy hat ein Akkord keine funktionale Rolle (Tonika/Dominante/Subdominante) — er hat eine Farbe. Die Akkordfolge folgt der Melodie und dem Klangbild, nicht der Spannungs-Auflösungs-Logik. Debussy mit T/SD/D zu analysieren gleicht dem Anwenden von Schachregeln auf Würfel — das Raster ist ungeeignet." },
  { q: "Was ist Planing (Homorrhythmie) im impressionistischen Stil?", opts: ["Zwei Stimmen mit gleichem Rhythmus aber verschiedenen Melodien", "Alle Stimmen bewegen sich im gleichen Rhythmus, mit demselben transponierten Akkordtyp — der Akkord gleitet als Klangblock", "Eine rhythmische Notationstechnik", "Ein Kanon auf derselben Tonhöhe"], a: 1, fb: "Planing oder Homorrhythmie: Alle Stimmen bewegen sich gemeinsam im gleichen Rhythmus und tragen denselben Akkordtyp. Ein Sextakkord gleitet über eine Tonleiter — alle Stimmen bewegen sich zusammen. Die Parallelquinten sind beabsichtigt — sie erzeugen den charakteristischen 'gleitenden Block'-Effekt Debussys." },
  { q: "Welchen harmonischen Effekt haben die von Debussy verwendeten 'mittelalterlichen offenen Quinten'?", opts: ["Sie erzeugen moderne dissonante Spannung", "Sie erzeugen einen Effekt archaischer Reinheit, wie Glocken oder Gregorianik — Rückkehr zu einer 'vortonalen' Konsonanz ohne Terz oder Quarte", "Sie ersetzen Dominantseptakkorde", "Sie evozieren immer japanische Musik"], a: 1, fb: "Offene Quinten (Grundton + Quinte, ohne Terz) evozieren mittelalterliches Organum und Gregorianik. Ohne Terz haben sie weder Dur- noch Moll-Qualität — sie klingen rein und zeitlos. Debussy verwendet sie für Effekte von Leere, Raum oder Archaismus (La Cathédrale Engloutie beginnt mit Quinten)." },
  { q: "Welche Tonleiter verwendet Debussy, um 'totales Schweben' ohne Leitton zu erzeugen?", opts: ["Melodische Moll-Tonleiter", "Ganztonleiter — 6 Ganztöne ohne Halbton, also ohne Leitton oder Unterleittton", "Oktatonische Tonleiter", "Phrygische Tonleiter"], a: 1, fb: "Die Ganztonleiter (C–D–E–Fis–Gis–Ais) hat keinen Halbton — also keine Leittonspannung. Kein Leitton zieht zur Tonika, kein Tritonus zieht zur Auflösung. Alle auf dieser Tonleiter gebauten Akkorde sind übermäßig. Der Effekt ist totales Schweben — die Musik will nirgendwohin." },
  { q: "Wie analysiert man die Struktur eines impressionistischen Stücks, wenn T/SD/D-Funktionen nicht zutreffen?", opts: ["Man kann es nicht analysieren", "Nach Farben und Registern: Quelltónleitern identifizieren, Textureffekte (Planing, Orgelpunkt), Klangfarbenwechsel und Zonen harmonischer Dichte", "Durch strenge Schenkersche Analyse", "Durch Vergleich mit klassischen Formen (Sonate, Rondo)"], a: 1, fb: "Die impressionistische Analyse identifiziert: 1/ Die Quelltönleiter (Ganzton, Oktatonik, Pentatonik); 2/ Die Texturtechnik (Planing, Orgelpunkt, offene Quinten); 3/ Die Akkordfarbe (Qualität, Erweiterungen); 4/ Das Register und die Dynamik. Diese 4 Parameter ersetzen die klassische Funktionsanalyse in Debussys Musik." },
  { q: "Debussys Pelléas et Mélisande wird oft als Modell impressionistischer Harmonik zitiert. Warum?", opts: ["Weil es ausschließlich Dominantseptakkorde verwendet", "Weil die Harmonik den Emotionen und Untertönen der Figuren folgt, ohne je eine klassische V–I-Kadenz zur Interpunktion zu verwenden — die Harmonik 'fließt' wie Emotionen", "Weil es vollständig im lydischen Modus komponiert ist", "Weil es Zwölftontechnik verwendet"], a: 1, fb: "Pelléas et Mélisande (1902) ist eine Opernrevolution: Die Harmonik vermeidet systematisch markante V→I-Kadenzen. Die harmonischen Dialoge folgen dem emotionalen Fluss der Figuren — der Akkord wechselt, wenn die Emotion sich ändert, nicht wenn die Musikform es verlangt. Eine völlig neue harmonische Dramaturgie." },
  { q: "Was ist Saties 'Musique d'ameublement' und wie antizipiert sie die moderne Musik?", opts: ["Musik um die Stille einer Oper zu füllen", "Musik, die nicht gehört werden soll — Klangkulisse ohne Spannung oder Auflösung, Vorläufer der Ambient-Musik und des Minimalismus", "Eine Kompositionstechnik für Soloklavier", "Ein neu erfundener Barockstil"], a: 1, fb: "Satie erfand die 'Musique d'ameublement' (1920) — Musik, die sich mit dem Umgebungslärm vermischen soll, wie ein akustisches Möbelstück. Sie hat keine dramatische Spannung oder Auflösung. Satie antizipierte Brian Eno (Ambient-Musik), Steve Reich (Minimalismus) und Lounge-Musik um 50 Jahre. Bei der Uraufführung setzte sich das Publikum und lauschte — Satie schrie wütend: 'Hoert nicht zu!'" },
  { q: "Was ist ein 'Polyakkord' (akkordliche Polytonalität) in Ravels Stil?", opts: ["Ein Akkord, der von mehreren Instrumenten gespielt wird", "Die Überlagerung zweier vollständiger, erkennbarer Akkorde — C-Dur + D-Dur = ein neuer hybrides harmonisches Cluster", "Ein Akkord mit 7 Noten", "Ein sehr schnell als Arpeggio gespielter Akkord"], a: 1, fb: "Bei Ravel erzeugt die Überlagerung zweier unterschiedlicher Akkorde eine neue Farbe. C-Dur + D-Dur = C–E–G–D–Fis–A. Die 6 Noten bilden keinen einfachen Akkord mehr — es ist eine Überlagerung zweier erkennbarer Akkorde. Ravel berechnet präzise, welche Noten eine reiche Farbe schaffen, ohne zu einem Cluster ohne Logik zu werden." },
  { q: "Wie erzeugt Ravel im Bolero progressive Spannung ohne Akkordwechsel?", opts: ["Er steigert das Tempo allmählich", "Er fügt sukzessive Instrumente hinzu — die Orchestrierung verdichtet sich, das Register erweitert sich, die Lautstärke steigt. Ein einziger C7-Akkord über 15 Minuten.", "Er moduliert in entfernte Tonarten", "Er wechselt den Rhythmus alle 8 Takte"], a: 1, fb: "Der Bolero ist ein einzigartiges orchestrales Meisterwerk: ein einziger Akkord (C-Dur/C7) und eine einzige Melodie 18 Mal wiederholt. Die Spannung entsteht ausschließlich durch progressive Orchestrierung — von der Soloflöte zum vollen Orchester. Es beweist, dass harmonische Progression nicht der einzige Spannungsmotor in der Musik ist." },
  { q: "Was ist der grundlegende Unterschied zwischen Debussys und Ravels kompositorischem Ansatz?", opts: ["Debussy komponiert für Orchester, Ravel nur für Klavier", "Debussy schafft intuitiv durch Klangbilder und -farben; Ravel kalkuliert mit architektonischer Strenge — gleiche impressionistische Oberfläche, entgegengesetzte Logiken", "Debussy verwendet Modi, Ravel nur das klassische Tonsystem", "Es gibt keinen stilistischen Unterschied zwischen ihnen"], a: 1, fb: "Debussy: organisches, intuitives Komponieren, das Farbe und Klangbild folgt. Ravel: architektonisches, kalkuliertes Komponieren mit nahezu mathematischer Strenge (er sagte, er habe 'den Geist eines Uhrmachers'). Gleiche impressionistische Oberfläche (farbige Akkorde, besondere Tonleitern), entgegengesetzte kompositorische Logiken. Debussy selbst unterschied klar zwischen beiden." },
  { q: "Was ist Ravels 'neoklassische Modalität'?", opts: ["Kirchentöne im Barockstil verwenden", "Zu alten Modi (Dorisch, Phrygisch, Lydisch) in einer modernen Musiksprache zurückkehren — die Pavane pour une infante défunte ist im Dorischen Modus auf g-Moll", "Im Wiener Klassikstil mit modalen Verzierungen komponieren", "Nur die modale Durtonleiter verwenden"], a: 1, fb: "Neoklassische Modalität bei Ravel bedeutet, kirchliche Modi (Dorisch, Phrygisch, Lydisch) in einem modernen harmonischen Kontext zu verwenden. Die Pavane pour une infante défunte ist in G-Dorisch-Moll (mit natürlichem Es, kein Fis als Leitton). Der abschließende Auflösungsakkord ist rein modal — keine klassische V7→Im-Kadenz." },
  { q: "Wie verändert eine hinzugefügte Note (6. oder 9.) die Farbe eines Durakkords im Ravelstil?", opts: ["Sie macht ihn zu Moll", "Sie fügt eine spezifische Brillanz, Fülle oder Sanftheit hinzu — CMaj6 (C–E–G–A) klingt 'zarter' und jazziger als reines CMaj", "Sie schafft eine unaufgeloeste Dissonanz", "Sie macht ihn identisch mit einem übermäßigen Akkord"], a: 1, fb: "Eine hinzugefügte 6. auf einem Durakkord (CMaj6: C–E–G–A) oder die hinzugefügte 9. (Cadd9: C–E–G–D) bereichern die Farbe ohne funktionale Spannung hinzuzufügen (keine Septime). CMaj6 klingt fast wie Am7 in zweiter Umkehrung — zarte Mehrdeutigkeit. Ravel verwendet diese 'angereicherten Akkorde', um seine charakteristische Klangfarbe zu schaffen." },
  { q: "Was ist das hauptsächliche harmonische Merkmal von Saties Gymnopédies?", opts: ["Schnelle und chromatische Progressionen", "Langsam schaukelnde große Septakkorde — Dmaj7–Gmaj7 oder ähnlich — statische und hypnotische Harmonik ohne dramatische Entwicklung", "Vierstimmige Fugen", "Oktatonische Tonleiter durch das gesamte Werk"], a: 1, fb: "Die Gymnopédies (1888) verwenden große Septakkorde in langsamem Schaukeln — typischerweise ein 'I'-Akkord und ein 'IV'-Akkord in wiederholtem Wechsel. Die Harmonik entwickelt sich nicht dramatisch — sie wechselt zwischen zwei Farben. Dieser statische, hypnotische Effekt ist eine Revolution: Die Musik hat kein harmonisches 'Ziel'." },
  { q: "Welcher Ambient-Komponist des 20. Jahrhunderts wird am häufigsten als Saties 'Erbe' genannt?", opts: ["John Williams", "Brian Eno — sein Album 'Ambient 1: Music for Airports' (1978) wendet genau die Philosophie der 'Musique d'ameublement' an", "Miles Davis", "Philip Glass"], a: 1, fb: "Brian Eno nannte Satie explizit als Inspiration für seine Ambient-Alben. 'Music for Airports' (1978) ist die moderne Verwirklichung der 'Musique d'ameublement': Musik, die nicht aufmerksam gehört werden soll und sich in die Umgebung einfügt. Eno erfand den Begriff 'Ambient Music' in direktem Bezug auf Satie." },
  { q: "Was ist Saties 'Vexations'-Technik?", opts: ["Ein chromatisches Kompositionsverfahren", "Ein Stück aus 180 Noten, das 840 Mal hintereinander gespielt wird (etwa 18 Stunden Musik) — erstes Beispiel radikalen Minimalismus und Dauer-Performance", "Eine Orgelpunkt-Technik", "Ein im Crescendo wiederholter Akkord"], a: 1, fb: "'Vexations' (1893) von Satie ist eine 52-sekuendige Partitur mit dem Vermerk 'in einem Zug 840 Mal zu spielen'. Die erste vollstaendige Auffuehrung durch John Cage und 12 Relais-Pianisten dauerte 1963 18h40. Es ist der erste Akt des radikalen Minimalismus und der Dauerkunst — 70 Jahre vor Steve Reich und Philip Glass." },
  { q: "Wie reagierten Debussy und Ravel darauf, unter dem Etikett 'Impressionismus' zusammengefasst zu werden?", opts: ["Beide akzeptierten den Begriff begeistert", "Debussy hasste diesen aus der Malerei entlehnten Begriff; Ravel beanspruchte ihn ebenfalls nicht — beide sahen sich schlicht als Komponisten französischer Musik", "Sie erfanden den Begriff selbst", "Sie schrieben gemeinsam ein Manifest über den musikalischen Impressionismus"], a: 1, fb: "Debussy lehnte den aus der Bildkritik entlehnten Begriff 'Impressionismus' besonders vehement ab. Er definierte sich als franzoesischen Komponisten, der 'etwas anderes' suchte. Ravel war mehrdeutiger, beanspruchte das Etikett aber auch nicht. Der musikalische Impressionismus ist eine von Kritikern, nicht von den Komponisten selbst geschaffene Kategorie." },
  { q: "Was ist die charakteristische harmonische Progression in Ravels Pavane pour une infante défunte?", opts: ["Vollstaendig auf Ganztonleiter ohne funktionalen Akkord", "Modale Progressionen in g-Dorisch-Moll — Fehlen des Leittons (Fis → F natuerlich), modale Kadenzen, die die Tonika im klassischen Sinne meiden", "Wiederholtes II–V–I in c-Moll", "Quintenzirkel nur im Dur-Modus"], a: 1, fb: "Ravels Pavane steht in g-Dorisch-Moll (Dorisch hat eine natuerliche 6. Stufe — Es wird zu E natuerlich). Die Kadenzen verwenden IVm (c-Moll) und bVII (F-Dur) — modale, keine tonalen Harmonien. Der Schlussakkord ist kein klassisches V7→Im, sondern eine weichere modale Kadenz. Das ist Ravels neoklassische Modalitaet in Aktion." },
];

const questionsEs: Question[] = [
  { q: "¿Cuál es la característica armónica principal del Prélude à l'après-midi d'un faune de Debussy?", opts: ["Una progresión clásica V–I repetida cada 8 compases", "El acorde inicial (Fa#Maj7) aparece sin preparación y no tiene función tonal — puro color sonoro durante 110 compases sin cadencia dominante-tónica", "Una fuga a cuatro voces", "Una escala de tonos enteros estricta a lo largo de toda la obra"], a: 1, fb: "El Prélude à l'après-midi d'un faune (1894) es revolucionario: el acorde inicial de Fa#Maj7 aparece sin contexto, sin preparación, como una aparición. Los 110 compases evitan cuidadosamente la cadencia clásica V→I. Debussy crea una 'armonía flotante' — la música existe en el presente sonoro, sin dirección funcional." },
  { q: "En la pieza 'Voiles' de Debussy, ¿qué dos escalas se utilizan?", opts: ["Escala mayor y escala menor armónica", "Escala de tonos enteros (sección principal) y escala pentatónica (sección central)", "Escala octatónica y escala lidia", "Escala cromática y escala de tonos enteros"], a: 1, fb: "'Voiles' es una obra maestra de la economía armónica: la pieza entera usa únicamente la escala de tonos enteros (sección principal, compases 1–47 y 64+) y la escala pentatónica (sección central, compases 48–63). Nunca ambas a la vez. Este cambio de escala marca la única 'modulación' de la pieza — sin acorde pivote clásico." },
  { q: "¿Qué es un 'pedal largo' en el estilo de Debussy?", opts: ["Una nota de bajo repetida muy rápidamente", "Un bajo inmóvil (nota sostenida o repetida) mientras la armonía cambia encima, creando un efecto de suspensión armónica", "Un acorde sostenido durante todo un compás", "Una nota ornamental en el pedal del piano"], a: 1, fb: "El pedal largo es una técnica de organum medieval reinventada por Debussy: el bajo permanece fijo (Do durante 8 compases) mientras la armonía encima se mueve libremente. El efecto es de suspensión temporal — el tiempo armónico se detiene en el bajo mientras el color cambia encima. Muy frecuente en Pelléas et Mélisande." },
  { q: "¿Cómo utiliza Debussy los acordes no funcionales?", opts: ["Los evita completamente y permanece en el sistema tonal clásico", "Los acordes siguen la línea melódica por su color sonoro, no por funciones armónicas T/SD/D — el acorde es una textura, no un rol", "Los usa únicamente en las cadencias", "Los usa solo en los pasajes octatónicos"], a: 1, fb: "En Debussy, un acorde no tiene rol funcional (tónica/dominante/subdominante) — tiene un color. La sucesión de acordes sigue la melodía y la imagen sonora, no la lógica tensión-resolución. Analizar a Debussy con T/SD/D equivale a aplicar las reglas del ajedrez a los dados — la rejilla es inapropiada." },
  { q: "¿Qué es el planing (homorritmia) en el estilo impresionista?", opts: ["Dos voces con el mismo ritmo pero diferentes melodías", "Todas las voces se mueven al mismo ritmo, con el mismo tipo de acorde transportado — el acorde se desplaza como un bloque sonoro", "Una técnica de notación rítmica", "Un canon a la misma altura"], a: 1, fb: "Planing u homorritmia: todas las voces se mueven juntas al mismo ritmo, llevando el mismo tipo de acorde. Un acorde de sexta se desliza sobre una escala — todas las voces se mueven juntas. Las quintas paralelas son intencionales — crean el característico efecto de 'bloque deslizante' de Debussy." },
  { q: "¿Cuál es el efecto armónico de las 'quintas abiertas medievales' utilizadas por Debussy?", opts: ["Crean tensión disonante moderna", "Crean un efecto de pureza arcaica, como campanas o canto llano — regreso a una consonancia 'pretonal' sin tercera ni cuarta", "Reemplazan los acordes de séptima de dominante", "Evocan siempre la música japonesa"], a: 1, fb: "Las quintas abiertas (fundamental + quinta, sin tercera) evocan el organum medieval y el canto llano. Sin tercera, no tienen ni calidad mayor ni menor — suenan puras y atemporales. Debussy las usa para efectos de vacío, espacio o arcaísmo (La Cathédrale Engloutie comienza con quintas)." },
  { q: "¿Qué escala usa Debussy para crear el 'flotamiento total' sin nota directriz?", opts: ["Escala menor melódica", "Escala de tonos enteros — 6 tonos enteros sin semitono, por lo tanto sin sensible ni subtónica", "Escala octatónica", "Escala frigia"], a: 1, fb: "La escala de tonos enteros (Do–Re–Mi–Fa#–Sol#–La#) no tiene semitono — por lo tanto ninguna tensión directriz. Ninguna sensible que tire hacia la tónica, ningún tritono que atraiga la resolución. Todos los acordes construidos sobre esta escala son aumentados. El efecto es el flotamiento total — la música no 'quiere' ir a ningún lugar." },
  { q: "¿Cómo se analiza la estructura de una pieza impresionista si las funciones T/SD/D no se aplican?", opts: ["No se puede analizar", "Por colores y registros: identificar escalas fuente, efectos de textura (planing, pedal), cambios de color sonoro y zonas de densidad armónica", "Por análisis schenkeriano estricto", "Por comparación con formas clásicas (sonata, rondó)"], a: 1, fb: "El análisis impresionista identifica: 1/ La escala fuente (tonos enteros, octatónica, pentatónica); 2/ La técnica de textura (planing, pedal, quintas abiertas); 3/ El color del acorde (calidad, extensiones); 4/ El registro y la dinámica. Estos 4 parámetros reemplazan el análisis funcional clásico en la música de Debussy." },
  { q: "Pelléas et Mélisande de Debussy se cita a menudo como modelo de armonía impresionista. ¿Por qué?", opts: ["Porque usa exclusivamente acordes de séptima de dominante", "Porque la armonía sigue las emociones y subtext de los personajes sin usar nunca una cadencia clásica V–I para puntuar — la armonía 'fluye' como las emociones", "Porque está compuesta enteramente en modo lidio", "Porque usa el dodecafonismo"], a: 1, fb: "Pelléas et Mélisande (1902) es una revolución operística: la armonía evita sistemáticamente las cadencias V→I marcadas. Los diálogos armónicos siguen el flujo emocional de los personajes — el acorde cambia cuando la emoción cambia, no cuando la forma musical lo exige. Una dramaturgia armónica enteramente nueva." },
  { q: "¿Qué es la 'música de muebles' inventada por Satie y cómo prefigura la música moderna?", opts: ["Música para llenar los silencios de una ópera", "Música hecha para no ser escuchada — fondo sonoro sin tensión ni resolución, precursor de la música ambient y el minimalismo", "Una técnica de composición para piano solo", "Un estilo de música barroca reinventado"], a: 1, fb: "Satie inventó la 'musique d'ameublement' (1920) — una música destinada a confundirse con el ruido ambiental, como un mueble sonoro. No tiene tensión dramática ni resolución. Satie prefiguró a Brian Eno (música ambient), Steve Reich (minimalismo) y la música lounge en 50 años. En su estreno: el público se sentó y escuchó — Satie furioso gritó: '¡No escuchen!'" },
  { q: "¿Qué es un 'poliacorde' (politonalidad acordal) en el estilo de Ravel?", opts: ["Un acorde tocado por varios instrumentos", "La superposición de dos acordes completos y reconocibles — DoMaj + ReMaj = un nuevo clúster armónico híbrido", "Un acorde con 7 notas", "Un acorde tocado muy rápidamente en arpegio"], a: 1, fb: "En Ravel, la superposición de dos acordes distintos crea un nuevo color. Do Mayor + Re Mayor = Do–Mi–Sol–Re–Fa#–La. Las 6 notas ya no forman un acorde simple — es una superposición de dos acordes reconocibles. Ravel calcula con precisión qué notas crean un color rico sin convertirse en un clúster sin lógica." },
  { q: "¿Cómo crea Ravel tensión progresiva en el Bolero sin cambiar de acorde?", opts: ["Acelera gradualmente el tempo", "Añade instrumentos sucesivamente — la orquestación se densifica, el registro se amplía, el volumen aumenta. Un solo acorde de Do7 durante 15 minutos.", "Modula hacia tonalidades lejanas", "Cambia el ritmo cada 8 compases"], a: 1, fb: "El Bolero es un tour de force orquestal único: un solo acorde (Do mayor/Do7) y una sola melodía repetida 18 veces. La tensión proviene únicamente de la orquestación progresiva — desde la flauta solista hasta la orquesta completa. Demuestra que la progresión armónica no es el único motor de tensión en la música." },
  { q: "¿Cuál es la diferencia fundamental entre el enfoque compositivo de Debussy y el de Ravel?", opts: ["Debussy compone para orquesta, Ravel solo para piano", "Debussy crea intuitivamente a través de imágenes y colores sonoros; Ravel calcula con rigor arquitectónico — misma superficie impresionista, lógicas opuestas", "Debussy usa modos, Ravel únicamente el sistema tonal clásico", "No hay ninguna diferencia estilística entre ellos"], a: 1, fb: "Debussy: composición orgánica, intuitiva, siguiendo el color y la imagen sonora. Ravel: composición arquitectónica, calculada, con rigor casi matemático (decía tener 'la mente de un relojero'). Misma superficie impresionista (acordes coloreados, escalas especiales), lógicas compositivas opuestas. El propio Debussy los distinguía claramente." },
  { q: "¿Qué es la 'modalidad neoclásica' de Ravel?", opts: ["Usar los modos eclesiásticos en estilo barroco", "Regresar a los modos antiguos (dórico, frigio, lidio) en un lenguaje musical moderno — la Pavane pour une infante défunte está en modo dórico sobre sol menor", "Componer en estilo clásico vienés con ornamentos modales", "Usar únicamente la escala mayor modal"], a: 1, fb: "La modalidad neoclásica en Ravel significa usar los modos eclesiásticos (dórico, frigio, lidio) en un contexto armónico moderno. La Pavane pour une infante défunte está en sol menor dórico (con mib natural, sin fa# sensible). El acorde resolutivo final es puramente modal — sin cadencia clásica V7→Im." },
  { q: "¿Cómo transforma una nota añadida (6.ª o 9.ª) el color de un acorde mayor en el estilo raveliano?", opts: ["Lo hace menor", "Añade un brillo, riqueza o dulzura específica — DoMaj6 (Do–Mi–Sol–La) suena más 'tierno' y jazzístico que DoMaj simple", "Crea una disonancia no resuelta", "Lo hace idéntico a un acorde aumentado"], a: 1, fb: "Una 6.ª añadida sobre un acorde mayor (DoMaj6: Do–Mi–Sol–La) o la 9.ª añadida (Doadd9: Do–Mi–Sol–Re) enriquecen el color sin añadir tensión funcional (sin séptima). DoMaj6 suena casi como Lam7 en segunda inversión — ambigüedad tierna. Ravel usa estos 'acordes enriquecidos' para crear su característico color armónico." },
  { q: "¿Cuál es la característica armónica principal de las Gymnopédies de Satie?", opts: ["Progresiones rápidas y cromáticas", "Acordes de séptima mayor lentos en balanceo — Remaj7–Solmaj7 o similar — armonía estática e hipnótica sin desarrollo dramático", "Fugas a cuatro voces", "Escala octatónica a lo largo de toda la obra"], a: 1, fb: "Las Gymnopédies (1888) usan acordes de séptima mayor en balanceo lento — típicamente un acorde 'I' y un acorde 'IV' en alternancia repetida. La armonía no progresa dramáticamente — oscila entre dos colores. Este efecto estático e hipnótico es una revolución: la música no tiene 'destino' armónico." },
  { q: "¿Qué compositor de música ambient del siglo XX es citado con más frecuencia como 'heredero' de Satie?", opts: ["John Williams", "Brian Eno — su álbum 'Ambient 1: Music for Airports' (1978) aplica exactamente la filosofía de la 'música de muebles'", "Miles Davis", "Philip Glass"], a: 1, fb: "Brian Eno citó explícitamente a Satie como inspiración para sus álbumes ambient. 'Music for Airports' (1978) es la realización moderna de la 'música de muebles': música para no ser escuchada atentamente, que se funde con el ambiente. Eno inventó el término 'ambient music' en referencia directa a Satie." },
  { q: "¿Qué es la técnica de las 'Vexations' de Satie?", opts: ["Un procedimiento de composición cromática", "Una pieza de 180 notas repetidas 840 veces seguidas (aproximadamente 18 horas de música) — primer ejemplo de minimalismo radical y performance de duración", "Una técnica de pedales largos", "Un acorde repetido en crescendo"], a: 1, fb: "'Vexations' (1893) de Satie es una partitura de 52 segundos con la indicación 'a tocar 840 veces seguidas'. Su primera interpretación completa por John Cage y 12 pianistas en relevo duró 18h40 en 1963. Es el primer acto del minimalismo radical y el arte-duración — 70 años antes que Steve Reich y Philip Glass." },
  { q: "¿Cómo reaccionaron Debussy y Ravel ante ser agrupados bajo la etiqueta 'impresionista'?", opts: ["Ambos aceptaron el término con entusiasmo", "Debussy odiaba este término tomado de la pintura; Ravel tampoco lo reivindicaba — ambos se consideraban simplemente compositores de música francesa", "Ellos mismos inventaron el término", "Escribieron juntos un manifiesto sobre el impresionismo musical"], a: 1, fb: "Debussy en particular rechazaba enérgicamente el término 'impresionista' tomado de la crítica pictórica. Se definía como compositor francés que buscaba 'algo diferente'. Ravel era más ambiguo pero tampoco reivindicaba la etiqueta. El impresionismo musical es una categoría creada por los críticos, no por los propios compositores." },
  { q: "¿Cuál es la progresión armónica característica de la Pavane pour une infante défunte de Ravel?", opts: ["Enteramente en escala de tonos enteros sin acorde funcional", "Progresiones modales en sol menor dórico — ausencia de sensible (Fa# → Fa natural), cadencias modales que evitan la tónica en el sentido clásico", "II–V–I en do menor repetido", "Ciclo de quintas en modo mayor únicamente"], a: 1, fb: "La Pavane de Ravel está en sol menor dórico (el dórico tiene un 6.º grado natural — mib se convierte en mi natural). Las cadencias usan el IVm (do menor) y el bVII (fa mayor) — armonías modales, no tonales. El acorde final no es un V7→Im clásico sino una cadencia modal más suave. Esta es la modalidad neoclásica raveliana en acción." },
];

const questionsIt: Question[] = [
  { q: "Qual è la caratteristica armonica principale del Prélude à l'après-midi d'un faune di Debussy?", opts: ["Una progressione classica V–I ripetuta ogni 8 battute", "Il primo accordo (Fa#Maj7) appare senza preparazione e non ha alcuna funzione tonale — puro colore sonoro per 110 battute senza cadenza dominante-tonica", "Una fuga a quattro voci", "Una scala per toni interi rigorosa per tutta l'opera"], a: 1, fb: "Il Prélude à l'après-midi d'un faune (1894) è rivoluzionario: l'accordo iniziale di Fa#Maj7 arriva senza contesto, senza preparazione, come un'apparizione. Le 110 battute evitano accuratamente la cadenza classica V→I. Debussy crea un'armonia 'fluttuante' — la musica esiste nel presente sonoro, senza direzione funzionale." },
  { q: "Nel brano 'Voiles' di Debussy, quali sono le due scale utilizzate?", opts: ["Scala maggiore e scala minore armonica", "Scala per toni interi (sezione principale) e scala pentatonica (sezione centrale)", "Scala ottatonica e scala lidia", "Scala cromatica e scala per toni interi"], a: 1, fb: "'Voiles' è un capolavoro di economia armonica: l'intero brano usa solo la scala per toni interi (sezione principale, battute 1–47 e 64+) e la scala pentatonica (sezione centrale, battute 48–63). Mai entrambe insieme. Questo cambio di scala segna l'unica 'modulazione' del brano — senza accordo pivot classico." },
  { q: "Cos'è un 'pedale lungo' nello stile di Debussy?", opts: ["Una nota del basso ripetuta molto rapidamente", "Un basso immobile (nota tenuta o ripetuta) mentre l'armonia cambia sopra, creando un effetto di sospensione armonica", "Un accordo tenuto per un'intera battuta", "Una nota ornamentale al pedale del pianoforte"], a: 1, fb: "Il pedale lungo è una tecnica di organum medievale reinventata da Debussy: il basso rimane fisso (Do per 8 battute) mentre l'armonia sopra si muove liberamente. L'effetto è di sospensione temporale — il tempo armonico si ferma al basso mentre il colore cambia sopra. Molto frequente in Pelléas et Mélisande." },
  { q: "Come utilizza Debussy gli accordi non funzionali?", opts: ["Li evita completamente e rimane nel sistema tonale classico", "Gli accordi seguono la linea melodica per il loro colore sonoro, non le funzioni armoniche T/SD/D — l'accordo è una texture, non un ruolo", "Li usa solo nelle cadenze", "Li usa solo nei passaggi ottatonici"], a: 1, fb: "In Debussy, un accordo non ha un ruolo funzionale (tonica/dominante/sottodominante) — ha un colore. La successione di accordi segue la melodia e l'immagine sonora, non la logica tensione-risoluzione. Analizzare Debussy con T/SD/D equivale ad applicare le regole degli scacchi ai dadi — la griglia è inappropriata." },
  { q: "Cos'è il planing (omoritmica) nello stile impressionista?", opts: ["Due voci con lo stesso ritmo ma melodie diverse", "Tutte le voci si muovono allo stesso ritmo, con lo stesso tipo di accordo trasposto — l'accordo scivola come un blocco sonoro", "Una tecnica di notazione ritmica", "Un canone alla stessa altezza"], a: 1, fb: "Planing o omoritmica: tutte le voci si muovono insieme allo stesso ritmo, portando lo stesso tipo di accordo. Un accordo di sesta scivola su una scala — tutte le voci si muovono insieme. Le quinte parallele sono intenzionali — creano il caratteristico effetto del 'blocco scorrevole' di Debussy." },
  { q: "Qual è l'effetto armonico delle 'quinte aperte medievali' usate da Debussy?", opts: ["Creano tensione dissonante moderna", "Creano un effetto di purezza arcaica, come campane o canto gregoriano — ritorno a una consonanza 'pretonale' senza terza né quarta", "Sostituiscono gli accordi di settima di dominante", "Evocano sempre la musica giapponese"], a: 1, fb: "Le quinte aperte (fondamentale + quinta, senza terza) evocano l'organum medievale e il canto gregoriano. Senza terza, non hanno né qualità maggiore né minore — suonano pure e atemporali. Debussy le usa per effetti di vuoto, spazio o arcaismo (La Cathédrale Engloutie inizia con delle quinte)." },
  { q: "Quale scala usa Debussy per creare il 'fluttuamento totale' senza nota direttrice?", opts: ["Scala minore melodica", "Scala per toni interi — 6 toni interi senza semitono, quindi senza sensibile né sottosensibile", "Scala ottatonica", "Scala frigia"], a: 1, fb: "La scala per toni interi (Do–Re–Mi–Fa#–Sol#–La#) non ha semitono — quindi nessuna tensione direttrice. Nessuna sensibile che tiri verso la tonica, nessun tritono che attiri la risoluzione. Tutti gli accordi costruiti su questa scala sono aumentati. L'effetto è il fluttuamento totale — la musica non 'vuole' andare da nessuna parte." },
  { q: "Come si analizza la struttura di un brano impressionista se le funzioni T/SD/D non si applicano?", opts: ["Non si può analizzare", "Per colori e registri: identificare le scale sorgente, gli effetti di texture (planing, pedale), i cambi di colore sonoro e le zone di densità armonica", "Con la stretta analisi schenkeriana", "Per confronto con le forme classiche (sonata, rondò)"], a: 1, fb: "L'analisi impressionista identifica: 1/ La scala sorgente (per toni, ottatonica, pentatonica); 2/ La tecnica di texture (planing, pedale, quinte aperte); 3/ Il colore dell'accordo (qualità, estensioni); 4/ Il registro e la dinamica. Questi 4 parametri sostituiscono l'analisi funzionale classica nella musica di Debussy." },
  { q: "Pelléas et Mélisande di Debussy è spesso citato come modello di armonia impressionista. Perché?", opts: ["Perché usa esclusivamente accordi di settima di dominante", "Perché l'armonia segue le emozioni e i sottotesti dei personaggi senza mai usare una cadenza classica V–I per punteggiare — l'armonia 'scorre' come le emozioni", "Perché è composto interamente in modo lidio", "Perché usa il dodecafonismo"], a: 1, fb: "Pelléas et Mélisande (1902) è una rivoluzione operistica: l'armonia evita sistematicamente le cadenze V→I marcate. I dialoghi armonici seguono il flusso emotivo dei personaggi — l'accordo cambia quando l'emozione cambia, non quando la forma musicale lo richiede. Una dramaturgia armonica completamente nuova." },
  { q: "Cos'è la 'musica d'arredamento' inventata da Satie e come prefigura la musica moderna?", opts: ["Musica per riempire i silenzi di un'opera", "Musica fatta per non essere ascoltata — sottofondo sonoro senza tensione né risoluzione, precursore della musica ambient e del minimalismo", "Una tecnica di composizione per pianoforte solo", "Uno stile di musica barocca reinventato"], a: 1, fb: "Satie inventò la 'musica d'arredamento' (1920) — una musica destinata a confondersi con il rumore ambientale, come un mobile sonoro. Non ha tensione drammatica né risoluzione. Satie ha anticipato Brian Eno (musica ambient), Steve Reich (minimalismo) e la musica lounge di 50 anni. Alla prima esecuzione: il pubblico si sedette e ascoltò — Satie furioso gridò: 'Non ascoltate!'" },
  { q: "Cos'è un 'poliacordo' (politonalità accordale) nello stile di Ravel?", opts: ["Un accordo suonato da più strumenti", "La sovrapposizione di due accordi completi e riconoscibili — DoMag + ReMag = un nuovo cluster armonico ibrido", "Un accordo con 7 note", "Un accordo suonato molto rapidamente in arpeggio"], a: 1, fb: "In Ravel, la sovrapposizione di due accordi distinti crea un nuovo colore. Do Maggiore + Re Maggiore = Do–Mi–Sol–Re–Fa#–La. Le 6 note non formano più un accordo semplice — è una sovrapposizione di due accordi riconoscibili. Ravel calcola con precisione quali note creano un colore ricco senza diventare un cluster senza logica." },
  { q: "Come crea Ravel una tensione progressiva nel Bolero senza cambiare accordo?", opts: ["Accelera il tempo progressivamente", "Aggiunge strumenti successivamente — l'orchestrazione si densifica, il registro si allarga, il volume aumenta. Un solo accordo di Do7 per 15 minuti.", "Modula verso tonalità lontane", "Cambia il ritmo ogni 8 battute"], a: 1, fb: "Il Bolero è un unico tour de force orchestrale: un solo accordo (Do maggiore/Do7) e una sola melodia ripetuta 18 volte. La tensione proviene unicamente dall'orchestrazione progressiva — dal flauto solista all'orchestra completa. Dimostra che la progressione armonica non è l'unico motore di tensione nella musica." },
  { q: "Qual è la differenza fondamentale tra l'approccio compositivo di Debussy e quello di Ravel?", opts: ["Debussy compone per orchestra, Ravel solo per pianoforte", "Debussy crea intuitivamente attraverso immagini e colori sonori; Ravel calcola con rigore architettonico — stessa superficie impressionista, logiche opposte", "Debussy usa i modi, Ravel solo il sistema tonale classico", "Non c'è alcuna differenza stilistica tra di loro"], a: 1, fb: "Debussy: composizione organica, intuitiva, seguendo il colore e l'immagine sonora. Ravel: composizione architettonica, calcolata, con rigore quasi matematico (diceva di avere 'la mente di un orologiaio'). Stessa superficie impressionista (accordi colorati, scale speciali), logiche compositive opposte. Debussy stesso li distingueva chiaramente." },
  { q: "Cos'è la 'modalità neoclassica' di Ravel?", opts: ["Usare i modi ecclesiastici in stile barocco", "Tornare ai modi antichi (dorico, frigio, lidio) in un linguaggio musicale moderno — la Pavane pour une infante défunte è in modo dorico su sol minore", "Comporre in stile classico viennese con ornamenti modali", "Usare solo la scala maggiore modale"], a: 1, fb: "La modalità neoclassica in Ravel significa usare i modi ecclesiastici (dorico, frigio, lidio) in un contesto armonico moderno. La Pavane pour une infante défunte è in sol minore dorico (con mib naturale, senza fa# sensibile). L'accordo risolutivo finale è puramente modale — nessuna cadenza classica V7→Im." },
  { q: "Come trasforma una nota aggiunta (6.a o 9.a) il colore di un accordo maggiore nello stile raveliano?", opts: ["Lo rende minore", "Aggiunge una brillantezza, ricchezza o dolcezza specifica — DoMag6 (Do–Mi–Sol–La) suona più 'dolce' e jazz di un semplice DoMag", "Crea una dissonanza non risolta", "Lo rende identico a un accordo aumentato"], a: 1, fb: "Una 6.a aggiunta su un accordo maggiore (DoMag6: Do–Mi–Sol–La) o la 9.a aggiunta (Doadd9: Do–Mi–Sol–Re) arricchiscono il colore senza aggiungere tensione funzionale (nessuna settima). DoMag6 suona quasi come Lam7 in secondo rivolto — ambiguità tenera. Ravel usa questi 'accordi arricchiti' per creare il suo caratteristico colore armonico." },
  { q: "Qual è la caratteristica armonica principale delle Gymnopédies di Satie?", opts: ["Progressioni rapide e cromatiche", "Accordi di settima maggiore lenti in bilancio — Remag7–Solmag7 o simile — armonia statica e ipnotica senza sviluppo drammatico", "Fughe a quattro voci", "Scala ottatonica per tutta l'opera"], a: 1, fb: "Le Gymnopédies (1888) usano accordi di settima maggiore in un lento dondolio — tipicamente un accordo 'I' e un accordo 'IV' in alternanza ripetuta. L'armonia non progredisce drammaticamente — oscilla tra due colori. Questo effetto statico e ipnotico è una rivoluzione: la musica non ha una 'destinazione' armonica." },
  { q: "Quale compositore di musica ambient del XX secolo è più spesso citato come 'erede' di Satie?", opts: ["John Williams", "Brian Eno — il suo album 'Ambient 1: Music for Airports' (1978) applica esattamente la filosofia della 'musica d'arredamento'", "Miles Davis", "Philip Glass"], a: 1, fb: "Brian Eno ha citato esplicitamente Satie come ispirazione per i suoi album ambient. 'Music for Airports' (1978) è la realizzazione moderna della 'musica d'arredamento': musica per non essere ascoltata attentamente, che si fonde con l'ambiente. Eno ha inventato il termine 'ambient music' in riferimento diretto a Satie." },
  { q: "Cos'è la tecnica delle 'Vexations' di Satie?", opts: ["Un procedimento di composizione cromatica", "Un brano di 180 note ripetute 840 volte di fila (circa 18 ore di musica) — primo esempio di minimalismo radicale e performance durativa", "Una tecnica di pedale lungo", "Un accordo ripetuto in crescendo"], a: 1, fb: "'Vexations' (1893) di Satie è una partitura di 52 secondi con l'indicazione 'da suonare 840 volte di seguito'. La prima esecuzione integrale da parte di John Cage e 12 pianisti a staffetta durò 18h40 nel 1963. È il primo atto del minimalismo radicale e dell'arte-durata — 70 anni prima di Steve Reich e Philip Glass." },
  { q: "Come reagirono Debussy e Ravel all'essere raggruppati sotto l'etichetta 'impressionista'?", opts: ["Entrambi accettarono il termine con entusiasmo", "Debussy odiava questo termine preso in prestito dalla pittura; Ravel non lo rivendicava nemmeno — entrambi si consideravano semplicemente compositori di musica francese", "Inventarono il termine loro stessi", "Scrissero insieme un manifesto sull'impressionismo musicale"], a: 1, fb: "Debussy in particolare rifiutava con veemenza il termine 'impressionista' preso in prestito dalla critica pittorica. Si definiva compositore francese alla ricerca di 'qualcosa d'altro'. Ravel era più ambiguo ma non rivendicava nemmeno lui l'etichetta. L'impressionismo musicale è una categoria creata dai critici, non dai compositori stessi." },
  { q: "Qual è la progressione armonica caratteristica della Pavane pour une infante défunte di Ravel?", opts: ["Interamente sulla scala per toni interi senza accordo funzionale", "Progressioni modali in sol minore dorico — assenza di sensibile (Fa# → Fa naturale), cadenze modali che evitano la tonica nel senso classico", "II–V–I in do minore ripetuto", "Ciclo di quinte in modo maggiore soltanto"], a: 1, fb: "La Pavana di Ravel è in sol minore dorico (il dorico ha un 6° grado naturale — mib diventa mi naturale). Le cadenze usano il IVm (do minore) e il bVII (fa maggiore) — armonie modali, non tonali. L'accordo finale non è un classico V7→Im ma una cadenza modale più morbida. Questa è la modalità neoclassica raveliana in azione." },
];

const questionsPt: Question[] = [
  { q: "Qual é a característica harmônica principal do Prélude à l'après-midi d'un faune de Debussy?", opts: ["Uma progressão clássica V–I repetida a cada 8 compassos", "O acorde inicial (Fa#Maj7) aparece sem preparação e não tem função tonal — pura cor sonora por 110 compassos sem cadência dominante-tônica", "Uma fuga a quatro vozes", "Uma escala de tons inteiros rigorosa ao longo de toda a obra"], a: 1, fb: "O Prélude à l'après-midi d'un faune (1894) é revolucionário: o acorde inicial de Fa#Maj7 chega sem contexto, sem preparação, como uma aparição. Os 110 compassos evitam cuidadosamente a cadência clássica V→I. Debussy cria uma 'harmonia flutuante' — a música existe no presente sonoro, sem direção funcional." },
  { q: "Na peça 'Voiles' de Debussy, quais são as duas escalas utilizadas?", opts: ["Escala maior e escala menor harmônica", "Escala de tons inteiros (seção principal) e escala pentatônica (seção central)", "Escala octatônica e escala lídia", "Escala cromática e escala de tons inteiros"], a: 1, fb: "'Voiles' é uma obra-prima de economia harmônica: a peça inteira usa apenas a escala de tons inteiros (seção principal, compassos 1–47 e 64+) e a escala pentatônica (seção central, compassos 48–63). Nunca as duas ao mesmo tempo. Essa mudança de escala marca a única 'modulação' da peça — sem acorde pivô clássico." },
  { q: "O que é um 'pedal longo' no estilo de Debussy?", opts: ["Uma nota de baixo repetida muito rapidamente", "Um baixo imóvel (nota sustentada ou repetida) enquanto a harmonia muda acima, criando um efeito de suspensão harmônica", "Um acorde sustentado durante um compasso inteiro", "Uma nota ornamental no pedal do piano"], a: 1, fb: "O pedal longo é uma técnica de organum medieval reinventada por Debussy: o baixo permanece fixo (Dó por 8 compassos) enquanto a harmonia acima se move livremente. O efeito é de suspensão temporal — o tempo harmônico para no baixo enquanto a cor muda acima. Muito frequente em Pelléas et Mélisande." },
  { q: "Como Debussy utiliza os acordes não funcionais?", opts: ["Ele os evita completamente e permanece no sistema tonal clássico", "Os acordes seguem a linha melódica pelo seu cor sonora, não por funções harmônicas T/SD/D — o acorde é uma textura, não um papel", "Ele os usa apenas nas cadências", "Ele os usa somente nos trechos octatônicos"], a: 1, fb: "Em Debussy, um acorde não tem papel funcional (tônica/dominante/subdominante) — tem uma cor. A sucessão de acordes segue a melodia e a imagem sonora, não a lógica tensão-resolução. Analisar Debussy com T/SD/D é como aplicar as regras do xadrez aos dados — a grelha é inadequada." },
  { q: "O que é planing (homorritmia) no estilo impressionista?", opts: ["Duas vozes com o mesmo ritmo mas melodias diferentes", "Todas as vozes se movem no mesmo ritmo, com o mesmo tipo de acorde transposto — o acorde desliza como um bloco sonoro", "Uma técnica de notação rítmica", "Um cânone na mesma altura"], a: 1, fb: "Planing ou homorritmia: todas as vozes se movem juntas no mesmo ritmo, carregando o mesmo tipo de acorde. Um acorde de sexta desliza sobre uma escala — todas as vozes se movem juntas. As quintas paralelas são intencionais — criam o característico efeito de 'bloco deslizante' de Debussy." },
  { q: "Qual é o efeito harmônico das 'quintas abertas medievais' utilizadas por Debussy?", opts: ["Criam tensão dissonante moderna", "Criam um efeito de pureza arcaica, como sinos ou canto gregoriano — retorno a uma consonância 'pré-tonal' sem terça nem quarta", "Substituem os acordes de sétima de dominante", "Evocam sempre a música japonesa"], a: 1, fb: "As quintas abertas (fundamental + quinta, sem terça) evocam o organum medieval e o canto gregoriano. Sem terça, não têm qualidade maior nem menor — soam puras e atemporais. Debussy as usa para efeitos de vazio, espaço ou arcaísmo (La Cathédrale Engloutie começa com quintas)." },
  { q: "Qual escala Debussy usa para criar a 'flutuação total' sem nota diretriz?", opts: ["Escala menor melódica", "Escala de tons inteiros — 6 tons inteiros sem semitom, portanto sem sensível nem subtônica", "Escala octatônica", "Escala frígia"], a: 1, fb: "A escala de tons inteiros (Dó–Ré–Mi–Fá#–Sol#–Lá#) não tem semitom — portanto nenhuma tensão diretriz. Nenhuma sensível que puxe para a tônica, nenhum trítono que atraia a resolução. Todos os acordes construídos sobre esta escala são aumentados. O efeito é a flutuação total — a música não 'quer' ir a lugar nenhum." },
  { q: "Como se analisa a estrutura de uma peça impressionista se as funções T/SD/D não se aplicam?", opts: ["Não se pode analisar", "Por cores e registros: identificar escalas-fonte, efeitos de textura (planing, pedal), mudanças de cor sonora e zonas de densidade harmônica", "Por análise schenkeriana rigorosa", "Por comparação com formas clássicas (sonata, rondó)"], a: 1, fb: "A análise impressionista identifica: 1/ A escala-fonte (tons inteiros, octatônica, pentatônica); 2/ A técnica de textura (planing, pedal, quintas abertas); 3/ A cor do acorde (qualidade, extensões); 4/ O registro e a dinâmica. Esses 4 parâmetros substituem a análise funcional clássica na música de Debussy." },
  { q: "Pelléas et Mélisande de Debussy é frequentemente citado como modelo de harmonia impressionista. Por quê?", opts: ["Porque usa exclusivamente acordes de sétima de dominante", "Porque a harmonia segue as emoções e subtextos das personagens sem nunca usar uma cadência clássica V–I para pontuar — a harmonia 'flui' como as emoções", "Porque é composto inteiramente em modo lídio", "Porque usa o dodecafonismo"], a: 1, fb: "Pelléas et Mélisande (1902) é uma revolução operística: a harmonia evita sistematicamente as cadências V→I marcadas. Os diálogos harmônicos seguem o fluxo emocional das personagens — o acorde muda quando a emoção muda, não quando a forma musical exige. Uma dramaturgia harmônica inteiramente nova." },
  { q: "O que é a 'música de mobiliário' inventada por Satie e como prefigura a música moderna?", opts: ["Música para preencher os silêncios de uma ópera", "Música feita para não ser escutada — fundo sonoro sem tensão nem resolução, precursor da música ambient e do minimalismo", "Uma técnica de composição para piano solo", "Um estilo de música barroca reinventado"], a: 1, fb: "Satie inventou a 'musique d'ameublement' (1920) — uma música destinada a confundir-se com o ruído ambiental, como um móvel sonoro. Não tem tensão dramática nem resolução. Satie antecipou Brian Eno (música ambient), Steve Reich (minimalismo) e a música lounge em 50 anos. Na sua estreia: o público sentou-se e ouviu — Satie furioso gritou: 'Não escutem!'" },
  { q: "O que é um 'poliacorde' (politonalidade acordal) no estilo de Ravel?", opts: ["Um acorde tocado por vários instrumentos", "A sobreposição de dois acordes completos e reconhecíveis — DóMaj + RéMaj = um novo cluster harmônico híbrido", "Um acorde com 7 notas", "Um acorde tocado muito rapidamente em arpejo"], a: 1, fb: "Em Ravel, a sobreposição de dois acordes distintos cria uma nova cor. Dó Maior + Ré Maior = Dó–Mi–Sol–Ré–Fá#–Lá. As 6 notas já não formam um acorde simples — é uma sobreposição de dois acordes reconhecíveis. Ravel calcula com precisão quais notas criam uma cor rica sem se tornar um cluster sem lógica." },
  { q: "Como Ravel cria tensão progressiva no Bolero sem mudar de acorde?", opts: ["Ele acelera o andamento progressivamente", "Ele adiciona instrumentos sucessivamente — a orquestração se adensa, o registro se alarga, o volume aumenta. Um único acorde de Dó7 por 15 minutos.", "Ele modula para tonalidades distantes", "Ele muda o ritmo a cada 8 compassos"], a: 1, fb: "O Bolero é um tour de force orquestral único: um único acorde (Dó maior/Dó7) e uma única melodia repetida 18 vezes. A tensão vem exclusivamente da orquestração progressiva — da flauta solo à orquestra completa. Demonstra que a progressão harmônica não é o único motor de tensão na música." },
  { q: "Qual é a diferença fundamental entre a abordagem composicional de Debussy e a de Ravel?", opts: ["Debussy compõe para orquestra, Ravel apenas para piano", "Debussy cria intuitivamente através de imagens e cores sonoras; Ravel calcula com rigor arquitetônico — mesma superfície impressionista, lógicas opostas", "Debussy usa modos, Ravel apenas o sistema tonal clássico", "Não há nenhuma diferença estilística entre eles"], a: 1, fb: "Debussy: composição orgânica, intuitiva, seguindo a cor e a imagem sonora. Ravel: composição arquitetônica, calculada, com rigor quase matemático (dizia ter 'a mente de um relojoeiro'). Mesma superfície impressionista (acordes coloridos, escalas especiais), lógicas composicionais opostas. O próprio Debussy os distinguia claramente." },
  { q: "O que é a 'modalidade neoclássica' de Ravel?", opts: ["Usar os modos eclesiásticos em estilo barroco", "Retornar aos modos antigos (dórico, frígio, lídio) numa linguagem musical moderna — a Pavane pour une infante défunte está em modo dórico em sol menor", "Compor em estilo clássico vienense com ornamentos modais", "Usar apenas a escala maior modal"], a: 1, fb: "A modalidade neoclássica em Ravel significa usar os modos eclesiásticos (dórico, frígio, lídio) num contexto harmônico moderno. A Pavane pour une infante défunte está em sol menor dórico (com mib natural, sem fá# sensível). O acorde resolutivo final é puramente modal — sem cadência clássica V7→Im." },
  { q: "Como uma nota acrescentada (6.ª ou 9.ª) transforma a cor de um acorde maior no estilo raveliano?", opts: ["Torna-o menor", "Acrescenta um brilho, riqueza ou doçura específicos — DóMaj6 (Dó–Mi–Sol–Lá) soa mais 'suave' e jazzístico do que DóMaj simples", "Cria uma dissonância não resolvida", "Torna-o idêntico a um acorde aumentado"], a: 1, fb: "Uma 6.ª acrescentada num acorde maior (DóMaj6: Dó–Mi–Sol–Lá) ou a 9.ª acrescentada (Dóadd9: Dó–Mi–Sol–Ré) enriquecem a cor sem adicionar tensão funcional (sem sétima). DóMaj6 soa quase como Lám7 em segunda inversão — ambiguidade terna. Ravel usa esses 'acordes enriquecidos' para criar a sua característica cor harmônica." },
  { q: "Qual é a característica harmônica principal das Gymnopédies de Satie?", opts: ["Progressões rápidas e cromáticas", "Acordes de sétima maior lentos em balanço — Rémaj7–Solmaj7 ou similar — harmonia estática e hipnótica sem desenvolvimento dramático", "Fugas a quatro vozes", "Escala octatônica ao longo de toda a obra"], a: 1, fb: "As Gymnopédies (1888) usam acordes de sétima maior em balanço lento — tipicamente um acorde 'I' e um acorde 'IV' em alternância repetida. A harmonia não progride dramaticamente — oscila entre duas cores. Este efeito estático e hipnótico é uma revolução: a música não tem um 'destino' harmônico." },
  { q: "Qual compositor de música ambient do século XX é mais frequentemente citado como 'herdeiro' de Satie?", opts: ["John Williams", "Brian Eno — o seu álbum 'Ambient 1: Music for Airports' (1978) aplica exatamente a filosofia da 'música de mobiliário'", "Miles Davis", "Philip Glass"], a: 1, fb: "Brian Eno citou explicitamente Satie como inspiração para os seus álbuns ambient. 'Music for Airports' (1978) é a realização moderna da 'música de mobiliário': música para não ser ouvida atentamente, que se funde com o ambiente. Eno inventou o termo 'ambient music' em referência direta a Satie." },
  { q: "O que é a técnica das 'Vexations' de Satie?", opts: ["Um procedimento de composição cromática", "Uma peça de 180 notas repetidas 840 vezes seguidas (cerca de 18 horas de música) — primeiro exemplo de minimalismo radical e performance de duração", "Uma técnica de pedal longo", "Um acorde repetido em crescendo"], a: 1, fb: "'Vexations' (1893) de Satie é uma partitura de 52 segundos com a indicação 'a tocar 840 vezes seguidas'. A sua primeira execução integral por John Cage e 12 pianistas em revezamento durou 18h40 em 1963. É o primeiro ato do minimalismo radical e da arte-duração — 70 anos antes de Steve Reich e Philip Glass." },
  { q: "Como Debussy e Ravel reagiram ao serem agrupados sob o rótulo 'impressionista'?", opts: ["Ambos aceitaram o termo com entusiasmo", "Debussy odiava este termo emprestado da pintura; Ravel também não o reivindicava — ambos se consideravam simplesmente compositores de música francesa", "Eles mesmos inventaram o termo", "Escreveram juntos um manifesto sobre o impressionismo musical"], a: 1, fb: "Debussy em particular rejeitava veementemente o termo 'impressionista' emprestado da crítica pictórica. Definia-se como compositor francês em busca de 'algo diferente'. Ravel era mais ambíguo mas também não reivindicava o rótulo. O impressionismo musical é uma categoria criada pelos críticos, não pelos próprios compositores." },
  { q: "Qual é a progressão harmônica característica da Pavane pour une infante défunte de Ravel?", opts: ["Inteiramente em escala de tons inteiros sem acorde funcional", "Progressões modais em sol menor dórico — ausência de sensível (Fá# → Fá natural), cadências modais que evitam a tônica no sentido clássico", "II–V–I em dó menor repetido", "Ciclo de quintas em modo maior apenas"], a: 1, fb: "A Pavana de Ravel está em sol menor dórico (o dórico tem um 6.º grau natural — mib torna-se mi natural). As cadências usam o IVm (dó menor) e o bVII (fá maior) — harmonias modais, não tonais. O acorde final não é um V7→Im clássico mas uma cadência modal mais suave. Esta é a modalidade neoclássica raveliana em ação." },
];

